const live = ($('API Live Scores').first().json.response || []);
const ft   = ($('API Today Scores').first().json.response || []);
const all  = [...live, ...ft];
const seen = new Set();
const scores = [];
for (const f of all) {
  const fid = f.fixture?.id;
  if (!fid || seen.has(fid)) continue;
  seen.add(fid);
  const st = f.fixture?.status?.short || '';
  let status = 'upcoming';
  if (['FT','AET','PEN'].includes(st)) status = 'completed';
  else if (['1H','HT','2H','ET','BT','P'].includes(st)) status = 'live';
  scores.push({
    fixtureId: fid,
    utcDate: f.fixture?.date || '',
    homeTeam: f.teams?.home?.name || '',
    awayTeam: f.teams?.away?.name || '',
    homeScore: f.goals?.home,
    awayScore: f.goals?.away,
    status,
    elapsed: f.fixture?.status?.elapsed || null
  });
}
return [{ json: { scores } }];

